import { useDeepCompareEffect } from '@guanghechen/react-hooks'
import React from 'react'
import type { IStorage } from '../types'

export function usePersisDataEffect<T extends Record<string, any>>(
  storage: IStorage<Partial<T>> | null,
  data: T,
  keys?: ReadonlyArray<keyof T>,
  anotherTriggers: ReadonlyArray<any> = [],
): void {
  const resolvedData: Partial<T> = React.useMemo(() => resolvePersistData(data, keys), [data, keys])

  useDeepCompareEffect(() => {
    if (storage == null) return
    void storage.save(resolvedData)
  }, [resolvedData, ...anotherTriggers])
}

export function resolvePersistData<T extends Record<string, any>>(
  data: T,
  keys?: ReadonlyArray<keyof T>,
): Partial<T> {
  if (keys === undefined) return data
  const result: Partial<T> = {}
  for (const key of keys) result[key] = data[key]
  return result
}
