import React from 'react'
import type { ISiteContext } from './context'
import { SiteContextType } from './context'
import { initialState } from './state'
import { createSiteStore } from './store'

export interface ISiteContextProvider {
  children: React.ReactNode
}

export const SiteContextProvider: React.FC<ISiteContextProvider> = props => {
  const context: ISiteContext = React.useMemo(
    () => ({ useSiteStore: createSiteStore(initialState()) }),
    [],
  )
  return <SiteContextType.Provider value={context}>{props.children}</SiteContextType.Provider>
}
