import type { IHostStore, ISerializer, IStorage } from './types'
import { createEmptyStorage, createStorage } from './util'

export * from './hook/useInitialData'
export * from './hook/usePersistDataEffect'
export * from './types'
export * from './util'

export function createLocalStorage<T>(key: string, serializer: ISerializer<T> = JSON): IStorage<T> {
  if (typeof localStorage === 'undefined') {
    console.error('Cannot find `localStorage`.')
    return createEmptyStorage<T>()
  }

  const hostStore: IHostStore = {
    get: key => localStorage.getItem(key),
    set: (key, value) => localStorage.setItem(key, value),
  }
  return createStorage(hostStore, key, serializer)
}
